-- BRK-10I Revenue Ops
CREATE TABLE IF NOT EXISTS public.brokerage_funding_verifications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), deal_id uuid NOT NULL REFERENCES public.deals(id), workflow_id uuid REFERENCES public.brokerage_closing_workflows(id), lender_bank_id uuid REFERENCES public.banks(id), funded_amount_cents integer NOT NULL, funded_at timestamptz NOT NULL, verification_source text NOT NULL CHECK (verification_source IN ('lender_confirmation','closing_statement','bank_statement','manual_ops','system')), verified_by_scope text NOT NULL CHECK (verified_by_scope IN ('lender','brokerage_ops','system')), verified_by_id text, evidence_document_id uuid REFERENCES public.deal_documents(id), status text NOT NULL DEFAULT 'verified' CHECK (status IN ('verified','corrected','voided')), metadata jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS brokerage_funding_verifications_deal_idx ON public.brokerage_funding_verifications (deal_id);
CREATE UNIQUE INDEX IF NOT EXISTS brokerage_funding_verifications_one_active ON public.brokerage_funding_verifications (deal_id) WHERE status = 'verified';
ALTER TABLE public.brokerage_funding_verifications ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.brokerage_revenue_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), deal_id uuid NOT NULL REFERENCES public.deals(id), fee_ledger_id uuid REFERENCES public.brokerage_fee_ledger(id), event_type text NOT NULL CHECK (event_type IN ('fee_estimated','fee_disclosed','fee_earned','fee_funded','fee_waived','fee_cancelled','funding_verified')), amount_cents integer, source text NOT NULL CHECK (source IN ('funding_verification','fee_ledger','ops','system')), metadata jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS brokerage_revenue_events_deal_idx ON public.brokerage_revenue_events (deal_id);
ALTER TABLE public.brokerage_revenue_events ENABLE ROW LEVEL SECURITY;
